<?php  namespace app\api\controller; use app\api\model\CmsModel; use core\basic\Controller; class GetDataController extends Controller{     protected $model;     public function __construct()     {         $this->model = new CmsModel();     }     public function news()     {         // 获取参数         $acode = request('acode', 'var') ?: get_default_lg();         $scode = request('scode', 'var') ?: '';         $page = request('page', 'int');         $num = request('num', 'int') ?: $this->config('pagesize');         $order = request('order');         $orderStr = is_null($order) ? 'id desc' : $order;         //$where[] = "a.scode in (".$scode.")";         $where = [];         $data = $this->model->getLists($acode, $scode, $num, $orderStr, $where);         json(1, $data);     } }